mapper.select:
SELECT id, template_name, project_type, product_line, description, status, create_time
FROM project_template

    deleted = 0

        AND template_name LIKE CONCAT('%', #{query.keyword}, '%')


        AND project_type = #{query.projectType}


        AND product_line = #{query.productLine}


        AND status = #{query.status}


ORDER BY create_time DESC
